#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; if(scanf("%d",&N)!=1) break;
        if(N%2==0) printf("true\n");
        else printf("false\n");
    }
    return 0;
}

